drop database if exists TFG;
create database TFG;
use TFG;

create table municipio(
    id int auto_increment primary key,
    nombre varchar(100),
    provincia varchar(100) not null
);

create table usuario(
    id int auto_increment primary key,
    nombre varchar(100),
    apellidos varchar(100),
    email varchar(100),
    contrasena varchar(255) not null,
    edad int,
    admin boolean default false,
    favoritos_ids text,
    constraint chk_edad check (edad BETWEEN 17 AND 60)
);

create table evento(
    id int auto_increment primary key,
    nombre varchar(100),
    tipo varchar(20) not null,
    descripcion_simple text,
    confirmada boolean,
    municipio_id int, 
    imagen text,
    constraint chk_tipo_evento check (tipo IN ('Cultural', 'Nocturno', 'Deportivo')),
    constraint fk_evento_municipio foreign key(municipio_id) references municipio(id)
);
create table comentario (
    id int auto_increment primary key,
    usuario_id int,
    evento_id int,
    texto text,
    calificacion int default 0,
    constraint chk_calificacion check (calificacion BETWEEN 0 AND 5),
    constraint fk_comentarios_usuario foreign key (usuario_id) references usuario(id),
    constraint fk_comentarios_evento foreign key (evento_id) references evento(id)
);

create table detalle_evento(
    id int auto_increment primary key,
    evento_id int not null,
    fecha_inicio datetime,
    fecha_fin datetime,
    subtipo varchar(100),
    descripcion_detallada text,
    localizacion_exacta varchar(200),
    entradas text,
    constraint fk_detalle_evento foreign key(evento_id) references evento(id)
);

